const labels = $json.labels || {};
const tramite_id = labels.tramite_id;

if (!tramite_id) {
    return [{ should_retry: false, message: 'No tramite_id in payload', tramite_id: 'unknown' }];
}

try {
    const response = await $http.request({
        method: 'POST',
        url: 'https://supabase.pash.uno/rest/v1/rpc/handle_tramite_retry_pro',
        body: { p_tramite_id: tramite_id, p_max_retries: 3 },
        headers: {
            'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpYXQiOjE3NzI3NTA5OTIsImV4cCI6MTg5MzQ1NjAwMCwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlzcyI6InN1cGFiYXNlIn0.arBCFrktA-kgkyz8ASjPbrs-FduxAQOHrA4bqes7Jbo',
            'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpYXQiOjE3NzI3NTA5OTIsImV4cCI6MTg5MzQ1NjAwMCwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlzcyI6InN1cGFiYXNlIn0.arBCFrktA-kgkyz8ASjPbrs-FduxAQOHrA4bqes7Jbo',
            'Content-Type': 'application/json'
        },
        json: true
    });

    const result = Array.isArray(response) ? response[0] : response;
    return [{
        should_retry: Boolean(result.out_should_retry),
        message: result.out_message || 'Sin mensaje',
        current_retry_count: result.out_current_retry_count || 0,
        circuit_state: result.out_circuit_state || 'unknown',
        tramite_id: tramite_id,
        step: labels.step || 'OCR'
    }];
} catch (error) {
    const errMsg = error.message || 'Error desconocido';
    return [{
        should_retry: false,
        message: 'RPC Error: ' + errMsg,
        tramite_id: tramite_id,
        step: labels.step || 'OCR'
    }];
}
